defmodule MyApp.ProductsController do
  plug :accepts, ["json"]

  alias MyApp.{Repo, Products}

  def list(conn) do
    products =
      %Query{}
      |> from(p in Products)
      |> where(^name == "my_product")

    case Repo.all(products) do
        [] ->
            conn
                |> put_status(:not_found)
                |> send_resp(:not_found, "Product not found")

        products ->
            conn
                    |> render("index.json-patch",
                        data: %{
                            products: products
                          }
                      )
    end
  end
end